<template>
  <div class="return-container">
    <div class="search-bar">
      <el-form :inline="true" :model="searchForm" class="search-form">
        <el-form-item label="订单号">
          <el-input v-model="searchForm.orderNo" placeholder="请输入订单号" class="search-input" />
        </el-form-item>
        <el-form-item label="用户昵称">
          <el-input v-model="searchForm.userName" placeholder="请输入用户昵称" class="search-input" />
        </el-form-item>
        <el-form-item label="售后类型">
          <el-select v-model="searchForm.type" placeholder="全部">
            <el-option label="全部" value="" />
            <el-option label="退货退款" value="return_refund" />
            <el-option label="仅退款" value="refund_only" />
          </el-select>
        </el-form-item>
        <el-form-item label="状态">
          <el-select v-model="searchForm.status" placeholder="全部">
            <el-option label="全部" value="" />
            <el-option label="待审核" value="pending" />
            <el-option label="审核通过" value="approved" />
            <el-option label="审核拒绝" value="rejected" />
            <el-option label="待退款" value="refund_pending" />
            <el-option label="已完成" value="completed" />
          </el-select>
        </el-form-item>
        <el-form-item>
          <el-button type="primary" @click="handleSearch">搜索</el-button>
          <el-button @click="resetForm">重置</el-button>
        </el-form-item>
      </el-form>
    </div>

    <el-table :data="tableData" border stripe :loading="loading" class="return-table">
      <el-table-column prop="id" label="售后编号" width="120" />
      <el-table-column prop="orderNo" label="订单号" width="180" />
      <el-table-column prop="type" label="售后类型" width="120">
        <template slot-scope="scope">
          <el-tag :type="scope.row.type === 'return_refund' ? 'warning' : 'info'">
            {{ scope.row.type === 'return_refund' ? '退货退款' : '仅退款' }}
          </el-tag>
        </template>
      </el-table-column>
      <el-table-column prop="productName" label="商品名称" />
      <el-table-column prop="amount" label="申请金额" width="100">
        <template slot-scope="scope">
          <span class="amount">¥{{ scope.row.amount }}</span>
        </template>
      </el-table-column>
      <el-table-column prop="userName" label="用户昵称" width="120" />
      <el-table-column prop="status" label="状态" width="100">
        <template slot-scope="scope">
          <el-tag :type="getStatusTagType(scope.row.status)">
            {{ getStatusText(scope.row.status) }}
          </el-tag>
        </template>
      </el-table-column>
      <el-table-column prop="createTime" label="申请时间" width="160" />
      <el-table-column label="操作" width="200">
        <template slot-scope="scope">
          <el-button size="mini" @click="showDetail(scope.row)">详情</el-button>
          <el-button 
            v-if="scope.row.status === 'pending'" 
            size="mini" 
            type="primary" 
            @click="handleApproval(scope.row)"
          >
            审核通过
          </el-button>
          <el-button 
            v-if="scope.row.status === 'pending'" 
            size="mini" 
            type="danger" 
            @click="handleReject(scope.row)"
          >
            拒绝
          </el-button>
          <el-button 
            v-if="scope.row.status === 'approved'" 
            size="mini" 
            type="success" 
            @click="handleRefund(scope.row)"
          >
            退款
          </el-button>
        </template>
      </el-table-column>
    </el-table>

    <el-empty v-if="!loading && tableData.length === 0" description="暂无数据" />

    <el-pagination
      :current-page="currentPage"
      :page-size="pageSize"
      :total="total"
      layout="total, prev, pager, next, jumper"
      @size-change="handleSizeChange"
      @current-change="handleCurrentChange"
    />

    <el-dialog title="售后详情" :visible.sync="detailVisible" width="600px">
      <el-form :model="detail" label-width="100px" class="detail-form">
        <el-form-item label="售后编号">
          <span>{{ detail.id }}</span>
        </el-form-item>
        <el-form-item label="订单号">
          <span>{{ detail.orderNo }}</span>
        </el-form-item>
        <el-form-item label="售后类型">
          <span>{{ detail.type === 'return_refund' ? '退货退款' : '仅退款' }}</span>
        </el-form-item>
        <el-form-item label="商品信息">
          <div>名称：{{ detail.productName }}</div>
          <div>规格：{{ detail.productSpec }}</div>
          <div>数量：{{ detail.quantity }}</div>
        </el-form-item>
        <el-form-item label="申请金额">
          <span class="amount-value">¥{{ detail.amount }}</span>
        </el-form-item>
        <el-form-item label="申请原因">
          <span>{{ detail.reason }}</span>
        </el-form-item>
        <el-form-item label="用户备注">
          <span>{{ detail.userRemark || '-' }}</span>
        </el-form-item>
        <el-form-item label="状态">
          <el-tag :type="getStatusTagType(detail.status)">{{ getStatusText(detail.status) }}</el-tag>
        </el-form-item>
        <el-form-item label="用户信息">
          <div>昵称：{{ detail.userName }}</div>
          <div>手机号：{{ detail.userPhone }}</div>
        </el-form-item>
        <el-form-item label="申请时间">
          <span>{{ detail.createTime }}</span>
        </el-form-item>
        <el-form-item label="处理日志">
          <el-timeline>
            <el-timeline-item v-for="(log, index) in detail.handlerLogs" :key="index">
              <template slot="dot">
                <i :class="getLogIconClass(log.type)"></i>
              </template>
              <div>{{ log.content }}</div>
              <div class="log-time">{{ log.time }}</div>
            </el-timeline-item>
          </el-timeline>
        </el-form-item>
      </el-form>
      <div slot="footer" class="dialog-footer">
        <el-button @click="detailVisible = false">关闭</el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>
import returnApi from '@/api/return'

export default {
  name: 'ReturnList',
  data() {
    return {
      searchForm: {
        orderNo: '',
        userName: '',
        type: '',
        status: ''
      },
      tableData: [],
      loading: false,
      currentPage: 1,
      pageSize: 10,
      total: 0,
      detailVisible: false,
      detail: {}
    }
  },
  mounted() {
    this.fetchList()
  },
  methods: {
    fetchList() {
      this.loading = true
      returnApi.getList({
        page: this.currentPage,
        size: this.pageSize,
        ...this.searchForm
      }).then(res => {
        if (res.code === 0) {
          this.tableData = res.data.list || []
          this.total = res.data.total || 0
        } else {
          this.$message.error(res.message || '获取售后列表失败')
        }
      }).catch(() => {
        this.$message.error('获取售后列表失败')
        this.tableData = []
        this.total = 0
      }).finally(() => {
        this.loading = false
      })
    },
    handleSearch() {
      this.currentPage = 1
      this.fetchList()
    },
    resetForm() {
      this.searchForm = {
        orderNo: '',
        userName: '',
        type: '',
        status: ''
      }
      this.currentPage = 1
      this.fetchList()
    },
    handleSizeChange(val) {
      this.pageSize = val
      this.fetchList()
    },
    handleCurrentChange(val) {
      this.currentPage = val
      this.fetchList()
    },
    showDetail(row) {
      returnApi.getDetail(row.id).then(res => {
        if (res.code === 0) {
          this.detail = res.data
          this.detailVisible = true
        } else {
          this.$message.error(res.message || '获取详情失败')
        }
      }).catch(() => {
        this.$message.error('获取详情失败')
      })
    },
    handleApproval(row) {
      this.$confirm('确定要审核通过该售后申请吗？', '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'warning'
      }).then(() => {
        returnApi.handle(row.id, { status: 'approved' }).then(res => {
          if (res.code === 0) {
            this.$message.success('审核通过成功')
            this.fetchList()
          } else {
            this.$message.error(res.message || '审核失败')
          }
        }).catch(() => this.$message.error('审核失败'))
      })
    },
    handleReject(row) {
      this.$prompt('请输入拒绝原因', '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        inputValidator: (val) => val && val.trim() ? true : '请输入拒绝原因'
      }).then(({ value }) => {
        returnApi.handle(row.id, { status: 'rejected', reason: value }).then(res => {
          if (res.code === 0) {
            this.$message.success('拒绝成功')
            this.fetchList()
          } else {
            this.$message.error(res.message || '操作失败')
          }
        }).catch(() => this.$message.error('操作失败'))
      })
    },
    handleRefund(row) {
      this.$confirm('确定要进行退款操作吗？', '提示', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'success'
      }).then(() => {
        returnApi.handle(row.id, { status: 'refunded' }).then(res => {
          if (res.code === 0) {
            this.$message.success('退款成功')
            this.fetchList()
          } else {
            this.$message.error(res.message || '退款失败')
          }
        }).catch(() => this.$message.error('退款失败'))
      })
    },
    getStatusText(status) {
      const statusMap = {
        pending: '待审核',
        approved: '审核通过',
        rejected: '审核拒绝',
        refund_pending: '待退款',
        completed: '已完成'
      }
      return statusMap[status] || status
    },
    getStatusTagType(status) {
      const typeMap = {
        pending: 'warning',
        approved: 'success',
        rejected: 'danger',
        refund_pending: 'info',
        completed: 'success'
      }
      return typeMap[status] || 'default'
    },
    getLogIconClass(type) {
      const iconMap = {
        apply: 'el-icon-plus',
        approve: 'el-icon-check',
        reject: 'el-icon-close',
        refund: 'el-icon-refresh'
      }
      return iconMap[type] || 'el-icon-info'
    }
  }
}
</script>

